<template><section class="space-y-6"><div><h1 class="text-3xl font-black text-white">Event Viewer</h1><p class="text-slate-400">Merged event stream from site-scoped security, purge, SSL, and operation sources.</p></div><DataTable title="Global events" :rows="rows" :columns="columns" /><pre class="card overflow-auto p-5 text-xs">{{ JSON.stringify(rows, null, 2) }}</pre></section></template>
<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'; import DataTable from '@/components/ui/DataTable.vue'; import { sitesApi } from '@/lib/api/sites'; import { loadSecurityEventsForSites } from '@/lib/api/securityEvents'; import { purgeApi } from '@/lib/api/purge'; import { formatDate } from '@/lib/utils/format'; import type { SecurityEvent, Site } from '@/types';
const sites = ref<Site[]>([]); const events = ref<Array<Record<string, unknown>>>([]); const columns = [{ key: 'site', label: 'Site' }, { key: 'type', label: 'Type' }, { key: 'severity', label: 'Severity' }, { key: 'decision', label: 'Decision' }, { key: 'time', label: 'Timestamp' }]; const rows = computed(() => events.value);
onMounted(async () => { sites.value = await sitesApi.list().catch(() => []); const security = await loadSecurityEventsForSites(sites.value).catch(() => [] as SecurityEvent[]); const purges = (await Promise.all(sites.value.map((s) => purgeApi.list(s.id).catch(() => [])))).flat(); events.value = [...security.map((e) => ({ site: e.site_name ?? e.site_id, type: e.type ?? 'security', severity: e.severity ?? 'info', decision: e.decision ?? e.action, time: formatDate(e.timestamp ?? e.created_at), raw: e })), ...purges.map((p) => ({ site: p.site_id, type: `purge:${p.type}`, severity: p.status === 'failed' ? 'critical' : 'info', decision: p.status, time: formatDate(p.created_at), raw: p }))]; });
</script>
